// 전역변수
scwin.pos_item = 0;
scwin.retrieveAfter = false; //조회직후여부확인
scwin.saveFlag = false; //save submitDone > true
scwin.rowFlag = "";
scwin.chkSkip = false; // rowPosition 변경 시 사용

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------  
scwin.onpageload = function () {
  scwin.f_setDSHeader();
  scwin.f_set("ONLOAD");
};

//-------------------------------------------------------------------------
// function name : f_set
// function desc : 화면 open시 초기 데이타 setting
//------------------------------------------------------------------------- 
scwin.f_set = function (gubun) {
  switch (gubun) {
    case "ONLOAD":
      $c.gus.cfDisableKey($p);
      cnd_ed_selpchItemCd.focus();
      $c.gus.cfDisableBtn($p, [btn_save]);
      break;
    case "RETRIEVE":
      $c.gus.cfEnableAllBtn($p);
      break;
    case "DELETE":
      $c.gus.cfDisableBtn($p);
      break;
  }
};

//-------------------------------------------------------------------------
// function name : f_setDSHeader
// function desc : Grid Header정보 Setting
//-------------------------------------------------------------------------
scwin.f_setDSHeader = function () {
  ds_cnd_item.set("selpchItemCd", "");
  ds_cnd_item.set("selpchItemNm", "");
  ds_cnd_item.set("ctrtTrfClsCd", "");
  ds_cnd_item.set("sellYn", 0);
  ds_cnd_item.set("pchsYn", 0);
  ds_cnd_item.set("useYn", 1);
};

//-------------------------------------------------------------------------
// function name : f_FieldClear
// function desc : 조회조건 Clear
//------------------------------------------------------------------------- 
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_cndArea);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (ds_item.getModifiedJSON().length > 0 && scwin.saveFlag == false) {
    if (await $c.win.confirm($p, MSG_CM_CRM_005)) {
      ds_item.setEventPause("", true);
      $c.sbm.execute($p, sbm_retrieve);
    }
  } else {
    ds_item.setEventPause("", true);
    $c.sbm.execute($p, sbm_retrieve);
  }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (await scwin.f_validate()) {
    if (ds_item.getModifiedIndex().length != 0) {
      if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
        //저장하시겠습니까?
        scwin.pos_item = ds_item.getRowPosition();
        if (!(await scwin.tbl_validate())) {
          return;
        }
        $c.sbm.execute($p, sbm_save);
      }
    } else {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["매출입항목관리"]); //@은(는) 변경된 사항이 없습니다
    }
  }
};

//-------------------------------------------------------------------------
// function name : f_addRow
// function desc : 매출입항목 행추가
//-------------------------------------------------------------------------
scwin.f_addRow = async function () {
  scwin.rowFlag = "add";
  var cnt = ds_item.getTotalRow();
  if (ds_item.getModifiedIndex().length != 0) {
    if (!(await scwin.f_validate())) {
      return;
    }
    if (!(await scwin.tbl_validate())) {
      return;
    }
  }
  scwin.chkSkip = true;
  ds_item.insertRow(cnt);
  ds_item.setCellData(cnt, "useYn", "1");
  gr_item.setFocusedCell(cnt, 0);
  txt_selpchItemNm.focus();
};

//-------------------------------------------------------------------------
// function name : f_deleteRow
// function desc : 매출입항목 행삭제
//-------------------------------------------------------------------------
scwin.f_deleteRow = function () {
  scwin.rowFlag = "del";
  var rowIdx = ds_item.getRowPosition();
  if (ds_item.getRowStatus(rowIdx) == "C") {
    ds_item.removeRow(rowIdx);
  } else {
    ds_item.deleteRow(rowIdx);
    ds_item.setRowPosition(rowIdx);
  }
  scwin.f_set("DELETE");
};

//-------------------------------------------------------------------------
// function name : f_cancelRow
// function desc : 매출입항목 행취소
//-------------------------------------------------------------------------
scwin.f_cancelRow = function () {
  scwin.rowFlag = "can";
  ds_item.setEventPause("", true);
  var rowIdx = ds_item.getRowPosition();
  if (ds_item.getRowStatus(rowIdx) == "C") {
    ds_item.removeRow(rowIdx);
  } else {
    ds_item.undoRow(rowIdx);
    scwin.sellYnText(rowIdx);
    ds_item.modifyRowStatus(rowIdx, "R");
  }
  ds_item.setEventPause("", false);
  scwin.f_set("RETRIEVE");
};

//-------------------------------------------------------------------------
// function name : f_init
// function desc : 매출입항목  화면 초기화 
//-------------------------------------------------------------------------
scwin.f_init = function () {};

//-------------------------------------------------------------------------
// function name : f_openPopUpBefore
// function desc : 팝업열기 전에 체크
//-------------------------------------------------------------------------
scwin.f_openPopUpBefore = function (gubun, nmObj, cdObj, pWinCloseTF) {
  if (nmObj.getValue() == nmObj.hidVal) {
    return;
  } else {
    if (nmObj.getValue() == "") {
      cdObj.setValue("");
      return;
    } else {
      cdObj.setValue("");
    }
  }
  scwin.f_openPopUp(gubun, pWinCloseTF);
};

//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : 팝업열기
// gubun : D=차변계정, C=대변계정
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (gubun, pWinCloseTF) {
  var pCode = "";
  var pName = "";
  var pWhere = "";
  var pTitle = "";
  var pWindowTitle = "";
  var compId = "";
  var callBackFun = "";
  if (gubun == "D1") {
    //매출차변계정코드
    // pSelectID = "retrieveAcctCdInfo"; 
    pCode = em_sellDrAcctCd.getValue();
    pName = txt_sellDrAcctNm.getValue();
    pWhere = ",,,D";
    pTitle = "매출차변계정코드,매출차변계정명";
    pWindowTitle = "매출차변계정코드조회,매출차변계정코드,매출차변계정명";
    compId = udc_sellDrAcctCd;
    callBackFun = scwin.udc_sellDrAcctCd_callBackFun;
  } else if (gubun == "C1") {
    //매출대변계정코드
    // pSelectID = "retrieveAcctCdInfo";
    pCode = em_sellCrAcctCd.getValue();
    pName = txt_sellCrAcctNm.getValue();
    pWhere = ",,,C";
    pTitle = "매출대변계정코드,매출대변계정명";
    pWindowTitle = "매출대변계정코드조회,매출대변계정코드,매출대변계정명";
    compId = udc_sellCrAcctCd;
    callBackFun = scwin.udc_sellCrAcctCd_callBackFun;
  } else if (gubun == "D2") {
    //매입차변계정코드
    // pSelectID = "retrieveAcctCdInfo";
    pCode = em_pchsDrAcctCd.getValue();
    pName = txt_pchsDrAcctNm.getValue();
    pWhere = ",,,D";
    pTitle = "매입차변계정코드,매입차변계정명";
    pWindowTitle = "매입차변계정코드조회,매입차변계정코드,매입차변계정명";
    compId = udc_pchsDrAcctCd;
    callBackFun = scwin.udc_pchsDrAcctCd_callBackFun;
  } else if (gubun == "C2") {
    //매입대변계정코드
    // pSelectID = "retrieveAcctCdInfo";
    pCode = em_pchsCrAcctCd.getValue();
    pName = txt_pchsCrAcctNm.getValue();
    pWhere = ",,,";
    pTitle = "매입대변계정코드,매입대변계정명";
    pWindowTitle = "매입대변계정코드조회,매입대변계정코드,매입대변계정명";
    compId = udc_pchsCrAcctCd;
    callBackFun = scwin.udc_pchsCrAcctCd_callBackFun;
  }
  compId.cfCommonPopUp(callBackFun // XML상의 SELECT ID	
  , pCode // 화면에서의 ??? Code Element의	Value
  , pName // 화면에서의 ??? Name Element의	Value
  , pWinCloseTF // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  , '5' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  , pTitle // Title순서	
  , '150,210' // 보여주는 각 컬럼들의 폭	
  , null // 컬럼중에서 숨기는	컬럼 지정	
  , pWhere // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  , '440' // POP-UP뛰을때 원도우의	사용자 정의	폭
  , '500' // POP-UP뛰을때 우도우의	사용자 정의	높이	
  , null // 윈도우 위치 Y좌표	
  , null // 윈도우 위치 X좌표
  , null // 중복체크여부	("F")
  , 'F' // 전체검색허용여부	("F")
  , pWindowTitle // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  );
};
