// 매출입구분 text 변경
scwin.sellYnText = function (i) {
  var sellYn = ds_item.getCellData(i, "sellYn");
  var pchsYn = ds_item.getCellData(i, "pchsYn");
  var strData;
  if (sellYn == 0) {
    strData = pchsYn == 0 ? "" : "매입";
  } else {
    strData = pchsYn == 0 ? "매출" : "매출,매입";
  }
  ds_item.setCellData(i, "sellYnText", strData);
};
scwin.chb_sellYn_onviewchange = function (info) {
  scwin.sellYnText(ds_item.getRowPosition());
};
scwin.chb_pchsYn_onviewchange = function (info) {
  scwin.sellYnText(ds_item.getRowPosition());
};

